import{_ as a,c as r,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"扩展 Superpowers | Superpowers 教程","description":"学习如何编写自定义技能、测试技能并向 Superpowers 项目贡献。掌握技能开发后，你可以定制专属的 AI 编码工作流。","frontmatter":{"title":"扩展 Superpowers | Superpowers 教程","sidebarTitle":"扩展","subtitle":"扩展 Superpowers","description":"学习如何编写自定义技能、测试技能并向 Superpowers 项目贡献。掌握技能开发后，你可以定制专属的 AI 编码工作流。","order":210},"headers":[],"relativePath":"zh/obra/superpowers/extending/index.md","filePath":"zh/obra/superpowers/extending/index.md"}'),o={name:"zh/obra/superpowers/extending/index.md"};function s(l,e,n,p,h,d){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="扩展-superpowers" tabindex="-1">扩展 Superpowers <a class="header-anchor" href="#扩展-superpowers" aria-label="Permalink to &quot;扩展 Superpowers&quot;">​</a></h1><p>本章节教你如何扩展 Superpowers：编写自定义技能、测试技能以及向项目贡献。学完后，你可以打造专属的 AI 编码工作流，并与社区分享你的成果。</p><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="编写自定义技能" tabindex="-1"><a href="./../writing-skills/">编写自定义技能</a> <a class="header-anchor" href="#编写自定义技能" aria-label="Permalink to &quot;[编写自定义技能](../writing-skills/)&quot;">​</a></h3><p>学会遵循最佳实践编写自己的技能。从技能结构、元数据定义到实际实现，完整掌握技能开发的每个环节。</p><h3 id="测试技能" tabindex="-1"><a href="./../testing-skills/">测试技能</a> <a class="header-anchor" href="#测试技能" aria-label="Permalink to &quot;[测试技能](../testing-skills/)&quot;">​</a></h3><p>使用子代理测试自己编写的技能，确保技能在各种场景下都能正确工作。学习编写测试用例和验证方法。</p><h3 id="贡献指南" tabindex="-1"><a href="./../contributing/">贡献指南</a> <a class="header-anchor" href="#贡献指南" aria-label="Permalink to &quot;[贡献指南](../contributing/)&quot;">​</a></h3><p>向 Superpowers 项目贡献技能和改进。了解贡献流程、代码规范和提交流程，让更多人受益于你的工作。</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>我们推荐按以下顺序学习本章节内容：</p><ol><li><strong>编写自定义技能</strong>：先掌握技能的基本结构和开发规范</li><li><strong>测试技能</strong>：确保你编写的技能质量可靠</li><li><strong>贡献指南</strong>：将优秀的技能分享给社区</li></ol><div class="tip custom-block"><p class="custom-block-title">小贴士</p><p>在学习编写技能前，建议你先完成 <a href="./../../start/using-skills/">如何使用技能</a> 和至少 2-3 个核心工作流的学习，这样能更好地理解技能的应用场景。</p></div><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>开始学习本章节前，请确保：</p><ul><li>✅ 已完成 <a href="./../../start/quick-start/">快速开始</a></li><li>✅ 已熟悉至少 2 个核心工作流（如 <a href="./../../core-workflows/design-workflow/">设计工作流</a> 和 <a href="./../../core-workflows/tdd-workflow/">TDD 工作流</a>）</li><li>✅ 了解基本的 Markdown 写作规范</li><li>✅ 有一定的编程经验（JavaScript/TypeScript 优先）</li></ul><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节学习后，你可以：</p><ul><li>查看 <a href="./../../faq/troubleshooting/">常见问题与故障排除</a> 解决使用中的问题</li><li>阅读 <a href="./../../faq/best-practices/">最佳实践与避坑指南</a> 深入了解使用技巧</li><li>参考 <a href="./../../appendix/skills-reference/">技能完整参考</a> 查看所有可用技能</li></ul>',19)])])}const f=a(o,[["render",s]]);export{c as __pageData,f as default};
